 jmp bleq6	lda 0 c10	add 0 3			; Increment adr2 by 8	add 2 0			; Increment adr1 by 8, move to ac0	lda 2 save2		; Recover frame pointer	eir			; Now reentrant	dsz 3 2			; Decrement and test count	 jmp bleq3		; More to dobleq4:	mkminusone 0 0 skp	; Here to return truebleq5:	 mkzero 0 0		; Here to return false	lda 3 1 2	jmp 1 3bleq6:	lda 2 save2		; Here to return false when	eir			;  inside fast loop	jmp bleq5c7:	7c10:	10save2:	0	.end